mapper.select:
SELECT overtime_id, user_id, overtime_date, overtime_start, overtime_end, overtime_hours, reason, remarks, created_at, updated_at, is_deleted
FROM overtime_records 
WHERE user_id = #{userId} 
AND overtime_date BETWEEN #{startDate} AND #{endDate}
AND is_deleted = false
ORDER BY overtime_date ASC

mapper.update:
UPDATE overtime_records
SET is_deleted = true,
    updated_at = NOW()
WHERE user_id = #{userId}
AND overtime_date = #{overtimeDate}
